SELECT user_id, COUNT(DISTINCT genome_id) AS number_of_annotated_genomes
FROM annotation_logs
GROUP BY user_id;

SELECT susd_id, susd_name, LENGTH(sequence) AS sequence_length
FROM susd
WHERE LENGTH(sequence) < (SELECT AVG(LENGTH(sequence)) FROM susd);

SELECT upload_user_id, COUNT(genome_id) AS genome_count
FROM genomes
GROUP BY upload_user_id;

SELECT COUNT(*)
FROM annotation_logs
WHERE annotation_type = 'SusC';

SELECT COUNT(*) 
FROM genomes 
WHERE upload_user_id = 2;

SELECT COUNT(*) 
FROM puls_cazymes 
WHERE is_confirmed = 1;

SELECT 
    (SELECT COUNT(*) FROM genomes) AS total_genomes,
    (SELECT COUNT(*) FROM contigs) AS total_contigs;

SELECT users.user_id, users.username, access_logs.genome_id, access_logs.pul_id, access_logs.access_date
FROM access_logs
JOIN users ON access_logs.user_id = users.user_id;

SELECT user_id, username, role
FROM users
WHERE last_login_date <= date('now', '-6 months');
